        prefixDiff[i + 1] = prefixDiff[i] + diff;
    }

    long[] suffixDiff = new long[n + 1];
    for (int i = n - 1; i >= 0; i--) {
        long diff = (1 - strategy[i]) * prices[i];
        suffixDiff[i] = suffixDiff[i + 1] + diff;
    }

    // Sliding window for the first half (0)
    long[] firstHalfSum = new long[n];
    long currentSum = 0;
