        currentSum += (0 - strategy[i]) * prices[i];
    }
    firstHalfSum[halfK - 1] = currentSum;
    for (int i = halfK; i < n; i++) {
        currentSum += (0 - strategy[i]) * prices[i];
        currentSum -= (0 - strategy[i - halfK]) * prices[i - halfK];
        firstHalfSum[i] = currentSum;
    }

    // Sliding window for the second half (1)
    long[] secondHalfSum = new long[n];
    currentSum = 0;
    for (int i = n - 1; i >= n - halfK; i--) {
        currentSum += (1 - strategy[i]) * prices[i];
    }
    secondHalfSum[n - halfK] = currentSum;
    for (int i = n - halfK - 1; i >= 0; i--) {
