        currentSum -= (1 - strategy[i + halfK]) * prices[i + halfK];
        secondHalfSum[i] = currentSum;
    }

    // Iterate over all possible windows of size k
    for (int i = 0; i <= n - (int) k; i++) {
        int j = i + (int) k;
        // The first half is i to i + halfK - 1 (set to 0)
        // The second half is i + halfK to j - 1 (set to 1)
        long firstPart = firstHalfSum[i + halfK - 1];
