    for (int i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    long maxProfit = originalProfit;
    int halfK = (int) (k / 2);

    // Precompute the prefix sums of the original strategy's profit
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + strategy[i] * prices[i];
    }

    // Precompute the profit if we modify the window [i, i + k -1]
    // The modification is: first halfK elements set to 0, last halfK elements set to 1
    // The profit change is: sum of (0 - strategy[i]) * prices[i] for first halfK elements
    //                     + sum of (1 - strategy[i]) * prices[i] for last halfK elements
    // So the total change is: sum of (-strategy[i] * prices[i]) for first halfK elements
    //                        + sum of (1 - strategy[i]) * prices[i] for last halfK elements

    // Compute the change for each possible window
    long currentChange = 0;
    // Initialize the first window [0, k-1]
    for (int i = 0; i < halfK; i++) {
        currentChange += (-strategy[i]) * prices[i];
    }
    for (int i = halfK; i < k; i++) {
        currentChange += (1 - strategy[i]) * prices[i];
    }
    maxProfit = Math.max(maxProfit, originalProfit + currentChange);

    // Slide the window from [1, k] to [n -k, n -1]
    for (int i = 1; i <= n - k; i++) {
        // Remove the contribution of the leftmost element (i-1)
        if (i - 1 < i - 1 + halfK) {
            currentChange -= (-strategy[i - 1]) * prices[i - 1];
        } else {
            currentChange -= (1 - strategy[i - 1]) * prices[i - 1];
        }

        // Add the contribution of the new rightmost element (i + k -1)
        if (i + halfK - 1 < i + k - 1) {
            currentChange += (1 - strategy[i + k - 1]) * prices[i + k - 1];
        } else {
            currentChange += (-strategy[i + k - 1]) * prices[i + k - 1];
        }

        // The first halfK elements in the new window are i to i + halfK -1
        // The last halfK elements are i + halfK to i + k -1
        // So we need to adjust for the elements that moved from first half to second half or vice versa
        // But since we are sliding by 1, only one element changes from first half to second half
        int mid = i + halfK - 1;
        currentChange -= (-strategy[mid]) * prices[mid];
        currentChange += (1 - strategy[mid]) * prices[mid];

        maxProfit = Math.max(maxProfit, originalProfit + currentChange);
    }

    return maxProfit;
