    // The modification is: first halfK elements set to 0, next halfK set to 1
    // So the profit for the window is sum(0 * prices[i..i+halfK-1]) + sum(1 * prices[i+halfK..i+k-1])
    // The delta is (sum(1 * prices[i+halfK..i+k-1]) - sum(strategy[i..i+halfK-1] * prices[i..i+halfK-1] + strategy[i+halfK..i+k-1] * prices[i+halfK..i+k-1]))

    // Compute the sum of prices in the second half of each possible window
    // We can use a sliding window approach for the second half sums
    if (n < k) {
        return originalProfit; // cannot modify any window of size k
    }

    // Compute the sum of the second half of the window when the window starts at i
    long[] secondHalfSum = new long[n - halfK + 1];
    for (int i = 0; i < halfK; i++) {
