    int halfK = (int) (k / 2);

    // Precompute the prefix sums of the original strategy * prices
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + strategy[i] * prices[i];
    }

    // Precompute the sum of prices for the first half (0) and second half (1) of the window
    long[] windowZeroSum = new long[n];
    long[] windowOneSum = new long[n];

    for (int i = 0; i < n; i++) {
        if (i < halfK) {
            windowZeroSum[i] = 0;
        } else {
            windowZeroSum[i] = (i >= halfK) ? 0 : 0;
        }
    }

    // Sliding window approach to compute the best window to modify
    long currentZeroSum = 0;
    long currentOneSum = 0;

    // Initialize the first window
    for (int i = 0; i < k; i++) {
        if (i < halfK) {
            currentZeroSum += 0 * prices[i]; // setting to 0
        } else {
            currentOneSum += 1 * prices[i]; // setting to 1
        }
    }

    long currentWindowProfit = currentZeroSum + currentOneSum;
    long originalWindowProfit = prefixSum[(int)k] - prefixSum[0];
    long delta = currentWindowProfit - originalWindowProfit;
    maxProfit = Math.max(maxProfit, originalProfit + delta);

    // Slide the window
    for (int i = (int)k; i < n; i++) {
        int left = i - (int)k;
        // Remove the leftmost element from the window
        if (left < halfK) {
            currentZeroSum -= 0 * prices[left];
        } else {
            currentOneSum -= 1 * prices[left];
        }

        // Add the new element to the window
        if (i - halfK < halfK) {
            currentZeroSum += 0 * prices[i];
        } else {
            currentOneSum += 1 * prices[i];
        }

        // Recompute the delta
        originalWindowProfit = prefixSum[i + 1] - prefixSum[left + 1];
        currentWindowProfit = currentZeroSum + currentOneSum;
        delta = currentWindowProfit - originalWindowProfit;
        maxProfit = Math.max(maxProfit, originalProfit + delta);
