            delta[i] = -strategy[i] * prices[i];
        } else {
            // For last k/2 elements, the change is (1 - strategy[i]) * prices[i]
            delta[i] = (1 - strategy[i]) * prices[i];
        }
    }

    // Compute sliding window sum of delta for window size k
    long currentWindow = 0;
    for (int i = 0; i < k; i++) {
        currentWindow += delta[i];
    }
    maxProfit = Math.max(maxProfit, originalProfit + currentWindow);

    for (int i = k; i < n; i++) {
        currentWindow += delta[i] - delta[i - k];
        maxProfit = Math.max(maxProfit, originalProfit + currentWindow);
    }

    return maxProfit;
